mapper.select:
SELECT m.id AS clientId, u.nickname AS name, u.age, u.profile_image AS profileImage, m.goals, m.height, m.weight, mpt.trainer_id, mpt.next_session, mpt.lesson_count, mpt.last_session, mpt.status FROM MEMBER m JOIN USER u ON m.user_id = u.id JOIN MEMBERSHIP_PT mpt ON mpt.id = ( SELECT id FROM MEMBERSHIP_PT WHERE member_id = m.id AND trainer_id = #{trainerId} ORDER BY id DESC LIMIT 1 ) WHERE u.is_deleted = 0
AND mpt.status = #{filter}
AND u.nickname LIKE CONCAT('%', #{search}, '%')
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM MEMBER m JOIN USER u ON m.user_id = u.id JOIN MEMBERSHIP_PT mpt ON mpt.id = ( SELECT id FROM MEMBERSHIP_PT WHERE member_id = m.id AND trainer_id = #{trainerId} ORDER BY id DESC LIMIT 1 ) WHERE u.is_deleted = 0
AND mpt.status = #{filter}
AND u.nickname LIKE CONCAT('%', #{search}, '%')
